def lexicographic_next(text):
    text = list(text)
    i = len(text) - 2
    while i >= 0 and text[i] >= text[i + 1]:
        i -= 1
    if i < 0:
        return None
    j = len(text) - 1
    while text[j] <= text[i]:
        j -= 1
    text[i], text[j] = text[j], text[i]
    text[i + 1:] = reversed(text[i + 1:])
    return ''.join(text)
