def evaluate_rpn(tokens):
    stack = []
    for token in tokens:
        if token.isdigit():
            stack.append(int(token))
        elif len(stack) < 2:
            raise ValueError("Malformed expression")
        else:
            b, a = stack.pop(), stack.pop()
            if token == '+':
                stack.append(a + b)
            elif token == '-':
                stack.append(a - b)
            elif token == '*':
                stack.append(a * b)
            elif token == '/':
                stack.append(int(a / b))
            else:
                raise ValueError("Unsupported operator")
    if len(stack) != 1:
        raise ValueError("Malformed expression")
    return stack[0]
```

