def interleaving_string(first, second, target):
    if len(target) != len(first) + len(second):
        return False

    dp = [[False] * (len(second) + 1) for _ in range(len(first) + 1)]
    dp[0][0] = True

    for i in range(len(first) + 1):
        for j in range(len(second) + 1):
            if i > 0:
                dp[i][j] |= dp[i-1][j] and first[i-1] == target[i+j-1]
            if j > 0:
                dp[i][j] |= dp[i][j-1] and second[j-1] == target[i+j-1]

    return dp[len(first)][len(second)]
